class Solution:
    def entityParser(self, text):
        """
        :type text: str
        :rtype: str
        """
        entities = {
            "&quot;": '"',
            "&apos;": "'",
            "&amp;": "&",
            "&gt;": ">",
            "&lt;": "<",
            "&frasl;": "/"
        }

        result = []
        i = 0

        while i < len(text):
            if text[i] == '&':
                # Try to match entity
                found = False
                for entity, char in entities.items():
                    if text[i:i+len(entity)] == entity:
                        result.append(char)
                        i += len(entity)
                        found = True
                        break

                if not found:
                    result.append(text[i])
                    i += 1
            else:
                result.append(text[i])
                i += 1

        return ''.join(result)
